// Maximum length for each Telegram message (keeping a small buffer for MarkdownV2)
const maxLength = 4000;

// Build the full message from extracted fields
const text = `
Info from chat:
City: ${$('Extract data from chat').first().json.output.city}
Country: ${$('Extract data from chat').first().json.output.country}
Citizenship: ${$('Extract data from chat').first().json.output.citizenship}
Crypto level: ${$('Extract data from chat').first().json.output.crypto_level}

---
${$('Extract data from chat').first().json.output.notes_base.content}
`;

// Function to split a string into smaller chunks
function chunkString(str, length) {
  const result = [];
  let i = 0;
  while (i < str.length) {
    result.push(str.slice(i, i + length));
    i += length;
  }
  return result;
}

// Return an array of objects, each will become one Telegram message
return chunkString(text, maxLength).map(t => ({ json: { text: t } }));
